  1404 | Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
  1405 |                                                      ICmpInst *ICmp2,
  1406 |                                                      bool IsAnd) {
  1407 |   CmpPredicate Pred1, Pred2;
  1408 |   Value *V1, *V2;
  1409 |   const APInt *C1, *C2;
  1410 |   if (!match(ICmp1, m_ICmp(Pred1, m_Value(V1), m_APInt(C1))) ||
  1411 |       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
  1412 |     return nullptr;
  1413 | 
  1414 |   // Look through add of a constant offset on V1, V2, or both operands. This
  1415 |   // allows us to interpret the V + C' < C'' range idiom into a proper range.
  1416 |   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
  1417 |   if (V1 != V2) {
  1418 |     Value *X;
  1419 |     if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
  1420 |       V1 = X;
  1421 |     if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
  1422 |       V2 = X;
  1423 |   }
  1424 | 
  1425 |   if (V1 != V2)
  1426 |     return nullptr;
  1427 | 
  1428 |   ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
  1429 |       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
  1430 |   if (Offset1)
  1431 |     CR1 = CR1.subtract(*Offset1);
  1432 | 
  1433 |   ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
  1434 |       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
  1435 |   if (Offset2)
  1436 |     CR2 = CR2.subtract(*Offset2);
  1437 | 
  1438 |   Type *Ty = V1->getType();
  1439 |   Value *NewV = V1;
  1440 |   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
  1441 |   if (!CR) {
  1442 |     if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
  1443 |         CR2.isWrappedSet())
  1444 |       return nullptr;
  1445 | 
  1446 |     // Check whether we have equal-size ranges that only differ by one bit.
  1447 |     // In that case we can apply a mask to map one range onto the other.
  1448 |     APInt LowerDiff = CR1.getLower() ^ CR2.getLower();
  1449 |     APInt UpperDiff = (CR1.getUpper() - 1) ^ (CR2.getUpper() - 1);
  1450 |     APInt CR1Size = CR1.getUpper() - CR1.getLower();
  1451 |     if (!LowerDiff.isPowerOf2() || LowerDiff != UpperDiff ||
  1452 |         CR1Size != CR2.getUpper() - CR2.getLower())
